 97→              <Route index element={<ProfilePostCards/>} />
 98→              <Route path='media' element={<ProfileMediaSection/>} />
 99→              <Route path='myOpinions' element={<MyOpinions/>}/>
100→              <Route path='stories' element={<ProfileStoriesSection/>}/>
101→            </Route>
102→
103→            <Route path='/visitProfile' element={<Visitprofile/>}>
104→              <Route index element={<VisitedProfilePostCards/>}/>
105→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
106→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
107→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
108→            </Route>
109→
110→            <Route path='/u/:username' element={<Visitprofile/>}>
111→              <Route index element={<VisitedProfilePostCards/>}/>
112→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
113→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
114→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
115→            </Route>
116→
117→            <Route path='/home' element={<HomePage/>}>
118→              <Route index element={<PostCards/>}/>
119→              <Route path='following' element={<PostCards/>}/>
120→              <Route path='for-you' element={<PostCards/>}/>
121→              <Route path='explore' element={<ExplorePage/>}/>
122→              <Route path='contentViewer' element={<ContentView/>}/>
123→              <Route path='post/:journalId' element={<ContentView/>}/>
124→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
125→              <Route path='bookmark' element={<Bookmarks/>}/>
126→              <Route path='opinions'element={<OpinionsPage/>}/>
127→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
128→
129→              <Route path='settings' element={<SettingsPage/>}/>
130→
131→              {/* Stories routes */}
132→              <Route path='stories' element={<StoryBrowser/>}/>
133→              <Route path='stories/library' element={<StoryLibrary/>}/>
134→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
135→              <Route path='stories/new' element={<StoryEditor/>}/>
136→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
137→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
138→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
139→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
140→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
141→
142→              {/* route for nested notifications */}
143→              <Route path='notifications' element={<Notifications/>}>
144→                <Route index element={<NotificationCards/>}/>
145→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
146→              </Route>  
147→            </Route>   
148→
149→            <Route path='/login' element={<LoginPage/>}/>
150→            <Route path='/signUp' element={<SignUp/>}/>
151→            <Route path='*' element={<NotFound/>}/>
152→          </Routes>
153→        </Suspense>
154→      </BrowserRouter>
155→    </LexicalComposer>
156→    </>
157→  )
158→}
159→
160→export default App
